    blades = []
    for _ in range(n):
        m, h = map(int, sys.stdin.readline().split())
        blades.append((m, h))

    # Sort blades by m in descending order
    blades.sort(key=lambda x: x[0], reverse=True)

    # Filter out blades that can't handle the starting size or are redundant
    filtered_blades = []
    max_m = 0
    min_h = float('inf')
    for m, h in blades:
        if m >= s:
            if h < min_h:
                min_h = h
                max_m = m
                filtered_blades.append((m, h))
        else:
            break

    blades = filtered_blades

    if not blades or blades[0][0] < s:
        print(-1)
        return

    # Create DP table
    dp = {}
    dp[s] = 0.0

