import sys

def double_up_game(sequence):
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]

        if i == j:
            memo[(i, j)] = sequence[i]
            return sequence[i]

        max_num = 0
        count = 0
        current = i
        while current <= j and sequence[current] == sequence[i]:
            count += 1
            current += 1

        if current <= j:
            max_num = max(max_num, dp(current, j))

        if count % 2 == 0:
            if current <= j:
                max_num = max(max_num, dp(i + count, j))
            else:
                max_num = sequence[i] * count

        memo[(i, j)] = max_num
        return max_num

    n = len(sequence)
    count = [0] * n
    count[0] = 1
    for i in range(1, n):
        if sequence[i] == sequence[i-1]:
            count[i] = count[i-1] + 1
        else:
            count[i] = 1

    def dp2(i, j):
        if (i, j) in memo:
            return memo[(i, j)]

        if i == j:
            memo[(i, j)] = sequence[i] * (count[i] // 2 * 2)
            return memo[(i, j)]

        if count[i] % 2 == 0:
            memo[(i, j)] = max(sequence[i] * count[i], dp2(i + count[i], j))
            return memo[(i, j)]

        max_num = dp2(i + 1, j)
        memo[(i, j)] = max_num
        return max_num

    return dp2(0, n - 1)

def main():
    n = int(sys.stdin.readline().strip())
    sequence = list(map(int, sys.stdin.readline().strip().split()))
    result = double_up_game(sequence)
    print(result)

if __name__ == "__main__":
    main()
