        blades = []
        for _ in range(n):
            m, h = map(float, sys.stdin.readline().strip().split())
            blades.append((m, h))
        blades.sort(key=lambda x: x[0], reverse=True)
        pq = []
        min_time = float('inf')
        for m, h in blades:
            if s <= m:
                heapq.heappush(pq, (h / math.log(2), s))
            else:
                if m <= t:
                    continue
                time_to_m = h * math.log(s / m) / math.log(2)
                heapq.heappush(pq, (h / math.log(2), m, time_to_m))
        while pq:
            rate, curr_size = heapq.heappop(pq)[:2]
            if len(pq) == 0 or curr_size <= t:
                min_time = min(min_time, rate * math.log(curr_size / t))
            else:
                min_time = min(min_time, rate * math.log(curr_size / t) + pq[0][2])
            if len(pq) > 0 and curr_size > t:
                next_rate, next_size, next_time_to_size = heapq.heappop(pq)
                time_to_next_size = rate * math.log(curr_size / next_size)
                heapq.heappush(pq, (next_rate, next_size, next_time_to_size + (time_to_next_size if len(pq) == 0 else next_time_to_size + pq[0][2])))
        if s <= t:
            min_time = 0.0
        print(min_time if min_time != float('inf') else -1)
    except Exception as e:
        # In a real application, you might want to log this error
        pass

